### **7. Account Resolution (accounts.ts)**

**Pattern to resolve runtime account state:**

```typescript
import { createAccountListHelpers } from "openclaw/plugin-sdk/account-helpers";
import { resolveMergedAccountConfig } from "openclaw/plugin-sdk/account-resolution";

export type ResolvedIrcAccount = {
  accountId: string;
  enabled: boolean;
  name?: string;
  configured: boolean;
  host: string;
  port: number;
  tls: boolean;
  nick: string;
  // ... all resolved fields
  config: IrcAccountConfig;  // Original config reference
};

const { listAccountIds: listIrcAccountIds, resolveDefaultAccountId } =
  createAccountListHelpers("irc", { normalizeAccountId });

function mergeIrcAccountConfig(cfg: CoreConfig, accountId: string): IrcAccountConfig {
  return resolveMergedAccountConfig({
    channelConfig: cfg.channels?.irc,
    accounts: cfg.channels?.irc?.accounts,
    accountId,
    omitKeys: ["defaultAccount"],
    nestedObjectKeys: ["nickserv"],
  });
}

export function resolveIrcAccount(opts: {
  cfg: CoreConfig;
  accountId?: string;
}): ResolvedIrcAccount {
  const accountId = normalizeAccountId(opts.accountId ?? resolveDefaultIrcAccountId(opts.cfg));
  const merged = mergeIrcAccountConfig(opts.cfg, accountId);

  // Resolve environment variables and file-based secrets
  const { password, source } = resolvePassword(accountId, merged);

  return {
    accountId,
    enabled: merged.enabled !== false,
    configured: !!merged.host && !!merged.nick,
    host: merged.host ?? "",
    port: merged.port ?? 6667,
    tls: merged.tls ?? true,
    nick: merged.nick ?? "",
    password,
    passwordSource: source,
    config: merged,
  };
}
```

**Key responsibilities:**
- List all configured account IDs
- Resolve default account ID
- Merge base + account-specific config
- Resolve secrets from env vars, files, or config
- Determine `configured` status
- Return fully resolved account object

