33	export function buildPassiveChannelStatusSummary<TExtra extends object>(
34	  snapshot: PassiveChannelStatusSnapshot,
35	  extra?: TExtra,
36	) {
37	  return {
38	    configured: snapshot.configured ?? false,
39	    ...(extra ?? ({} as TExtra)),
40	    running: snapshot.running ?? false,
41	    lastStartAt: snapshot.lastStartAt ?? null,
42	    lastStopAt: snapshot.lastStopAt ?? null,
