109	export function readStatusIssueFields<TField extends string>(
110	  value: unknown,
111	  fields: readonly TField[],
112	): Record<TField, unknown> | null {
113	  if (!value || typeof value !== "object") {
114	    return null;
115	  }
116	  const record = value as Record<string, unknown>;
117	  const result = {} as Record<TField, unknown>;
118	  for (const field of fields) {
119	    result[field] = record[field];
120	  }
121	  return result;
