128	export function createDeferred<T>() {
129	  let resolve!: (value: T | PromiseLike<T>) => void;
130	  let reject!: (reason?: unknown) => void;
131	  const promise = new Promise<T>((res, rej) => {
132	    resolve = res;
133	    reject = rej;
134	  });
135	  return { promise, resolve, reject };
136	}
