316	/** Build a config-issue collector from snapshot-safe source metadata only. */
317	export function createDependentCredentialStatusIssueCollector(options: {
318	  channel: string;
319	  dependencySourceKey: string;
320	  missingPrimaryMessage: string;
321	  missingDependentMessage: string;
322	  isDependencyConfigured?: ((value: unknown) => boolean) | undefined;
323	}) {
324	  const isDependencyConfigured =
325	    options.isDependencyConfigured ??
326	    ((value: unknown) => typeof value === "string" && value.trim().length > 0 && value !== "none");
327	
328	  return (accounts: ConfigIssueAccount[]): ChannelStatusIssue[] =>
329	    accounts.flatMap((account) => {
330	      if (account.configured !== false) {
331	        return [];
332	      }
333	      return [
334	        {
335	          channel: options.channel,
336	          accountId: account.accountId ?? "",
337	          kind: "config",
338	          message: isDependencyConfigured(account[options.dependencySourceKey])
339	            ? options.missingDependentMessage
340	            : options.missingPrimaryMessage,
341	        },
342	      ];
343	    });
344	}
