346	/** Convert account runtime errors into the generic channel status issue format. */
347	export function collectStatusIssuesFromLastError(
348	  channel: string,
349	  accounts: Array<{ accountId: string; lastError?: unknown }>,
350	): ChannelStatusIssue[] {
351	  return accounts.flatMap((account) => {
352	    const lastError = typeof account.lastError === "string" ? account.lastError.trim() : "";
353	    if (!lastError) {
354	      return [];
355	    }
356	    return [
357	      {
358	        channel,
359	        accountId: account.accountId,
360	        kind: "runtime",
361	        message: `Channel error: ${lastError}`,
362	      },
363	    ];
364	  });
365	}
