3	type CloseAwareServer = {
4	  once: (event: "close", listener: () => void) => unknown;
5	};
6	
7	type PassiveAccountLifecycleParams<Handle> = {
8	  abortSignal?: AbortSignal;
9	  start: () => Promise<Handle>;
10	  stop?: (handle: Handle) => void | Promise<void>;
11	  onStop?: () => void | Promise<void>;
12	};
13	
14	/** Bind a fixed account id into a status writer so lifecycle code can emit partial snapshots. */
15	export function createAccountStatusSink(params: {
16	  accountId: string;
17	  setStatus: (next: ChannelAccountSnapshot) => void;
18	}): (patch: Omit<ChannelAccountSnapshot, "accountId">) => void {
19	  return (patch) => {
20	    params.setStatus({ accountId: params.accountId, ...patch });
21	  };
22	}
