24	/**
25	 * Return a promise that resolves when the signal is aborted.
26	 *
27	 * If no signal is provided, the promise stays pending forever. When provided,
28	 * `onAbort` runs once before the promise resolves.
29	 */
30	export function waitUntilAbort(
31	  signal?: AbortSignal,
32	  onAbort?: () => void | Promise<void>,
33	): Promise<void> {
34	  return new Promise<void>((resolve, reject) => {
35	    const complete = () => {
36	      Promise.resolve(onAbort?.()).then(() => resolve(), reject);
37	    };
38	    if (!signal) {
39	      return;
40	    }
41	    if (signal.aborted) {
42	      complete();
43	      return;
44	    }
45	    signal.addEventListener("abort", complete, { once: true });
46	  });
47	}
48	
49	/**
50	 * Keep a passive account task alive until abort, then run optional cleanup.
51	 */
52	export async function runPassiveAccountLifecycle<Handle>(
53	  params: PassiveAccountLifecycleParams<Handle>,
54	): Promise<void> {
55	  const handle = await params.start();
56	
57	  try {
58	    await waitUntilAbort(params.abortSignal);
59	  } finally {
60	    await params.stop?.(handle);
61	    await params.onStop?.();
62	  }
63	}
64	
65	/**
66	 * Keep a channel/provider task pending until the HTTP server closes.
67	 *
68	 * When an abort signal is provided, `onAbort` is invoked once and should
69	 * trigger server shutdown. The returned promise resolves only after `close`.
70	 */
71	export async function keepHttpServerTaskAlive(params: {
72	  server: CloseAwareServer;
73	  abortSignal?: AbortSignal;
74	  onAbort?: () => void | Promise<void>;
75	}): Promise<void> {
76	  const { server, abortSignal, onAbort } = params;
77	  let abortTask: Promise<void> = Promise.resolve();
78	  let abortTriggered = false;
79	
80	  const triggerAbort = () => {
81	    if (abortTriggered) {
82	      return;
83	    }
84	    abortTriggered = true;
85	    abortTask = Promise.resolve(onAbort?.()).then(() => undefined);
86	  };
87	
88	  const onAbortSignal = () => {
89	    triggerAbort();
90	  };
91	
92	  if (abortSignal) {
93	    if (abortSignal.aborted) {
94	      triggerAbort();
95	    } else {
96	      abortSignal.addEventListener("abort", onAbortSignal, { once: true });
97	    }
98	  }
99	
100	  await new Promise<void>((resolve) => {
101	    server.once("close", () => resolve());
102	  });
103	
104	  if (abortSignal) {
105	    abortSignal.removeEventListener("abort", onAbortSignal);
106	  }
107	  await abortTask;
108	}
