import type { PulseBoardBoardConfig } from "./types.js";

type GroupMatch = {
  boardConfig: PulseBoardBoardConfig | undefined;
  wildcardConfig: PulseBoardBoardConfig | undefined;
};

/**
 * Find the matching board config for a target from the groups record.
 * Falls back to the wildcard ("*") entry when no exact match is found.
 */
export function resolvePulseBoardGroupMatch(params: {
  groups: Record<string, PulseBoardBoardConfig> | undefined;
  target: string;
}): GroupMatch {
  const { groups, target } = params;
  if (!groups) {
    return { boardConfig: undefined, wildcardConfig: undefined };
  }
  const normalized = target.toLowerCase();
  const boardConfig = groups[normalized];
  const wildcardConfig = groups["*"];
  return { boardConfig, wildcardConfig };
}

/** Resolve whether @mention is required for a board. */
export function resolvePulseBoardRequireMention(params: {
  boardConfig: PulseBoardBoardConfig | undefined;
  wildcardConfig: PulseBoardBoardConfig | undefined;
}): boolean {
  // Explicit board config takes precedence over wildcard, default true.
  return params.boardConfig?.requireMention ?? params.wildcardConfig?.requireMention ?? true;
}

