import { afterEach, describe, expect, it } from "vitest";
import { pulseBoardPlugin } from "./channel.js";
import { clearPulseBoardRuntime } from "./runtime.js";
import {
  normalizePulseBoardTarget,
  isBoardTarget,
  looksLikePulseBoardTargetId,
  normalizePulseBoardAllowEntry,
} from "./normalize.js";
import {
  resolvePulseBoardGroupMatch,
  resolvePulseBoardRequireMention,
} from "./policy.js";

describe("pulseBoardPlugin", () => {
  afterEach(() => {
    clearPulseBoardRuntime();
  });

  describe("meta", () => {
    it("has correct id", () => {
      expect(pulseBoardPlugin.id).toBe("pulseboard");
    });

    it("has required meta fields", () => {
      expect(pulseBoardPlugin.meta.label).toBe("PulseBoard");
      expect(pulseBoardPlugin.meta.docsPath).toBe("/channels/pulseboard");
    });
  });

  describe("capabilities", () => {
    it("supports direct messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("direct");
    });

    it("supports group messages", () => {
      expect(pulseBoardPlugin.capabilities.chatTypes).toContain("group");
    });

    it("does not support media", () => {
      expect(pulseBoardPlugin.capabilities.media).toBe(false);
    });
  });

  describe("outbound chunking", () => {
    it("chunks outbound text without requiring runtime initialization", () => {
      const chunker = pulseBoardPlugin.outbound?.chunker;
      if (!chunker) {
        throw new Error("pulseboard outbound.chunker unavailable");
      }
      expect(chunker("alpha beta", 5)).toEqual(["alpha", "beta"]);
    });

    it("respects the 4000-character text chunk limit", () => {
      const chunker = pulseBoardPlugin.outbound?.chunker;
      if (!chunker) {
        throw new Error("pulseboard outbound.chunker unavailable");
      }
      // A message under the limit should not be chunked.
      const shortMessage = "a".repeat(3999);
      expect(chunker(shortMessage, 4000)).toEqual([shortMessage]);

      // A message over the limit should be chunked.
      const longMessage = "word ".repeat(1000).trim();
      const chunks = chunker(longMessage, 4000);
      expect(chunks.length).toBeGreaterThan(1);
      for (const chunk of chunks) {
        expect(chunk.length).toBeLessThanOrEqual(4000);
      }
    });
  });
});

describe("normalize", () => {
  it("normalizes targets to lowercase", () => {
    expect(normalizePulseBoardTarget("Alice")).toBe("alice");
    expect(normalizePulseBoardTarget("#General")).toBe("#general");
  });

  it("returns null for empty targets", () => {
    expect(normalizePulseBoardTarget("")).toBeNull();
    expect(normalizePulseBoardTarget("  ")).toBeNull();
  });

  it("identifies board targets", () => {
    expect(isBoardTarget("#general")).toBe(true);
    expect(isBoardTarget("#announcements")).toBe(true);
    expect(isBoardTarget("alice")).toBe(false);
  });

  it("recognizes valid target ids", () => {
    expect(looksLikePulseBoardTargetId("#general")).toBe(true);
    expect(looksLikePulseBoardTargetId("alice")).toBe(true);
    expect(looksLikePulseBoardTargetId("user-name")).toBe(true);
    expect(looksLikePulseBoardTargetId("")).toBe(false);
  });

  it("normalizes allow entries", () => {
    expect(normalizePulseBoardAllowEntry("  Alice  ")).toBe("alice");
    expect(normalizePulseBoardAllowEntry("BOB")).toBe("bob");
  });
});

describe("policy", () => {
  it("resolves board config from groups", () => {
    const groups = {
      "#general": { requireMention: false },
      "*": { requireMention: true },
    };
    const match = resolvePulseBoardGroupMatch({ groups, target: "#general" });
    expect(match.boardConfig).toEqual({ requireMention: false });
    expect(match.wildcardConfig).toEqual({ requireMention: true });
  });

  it("falls back to wildcard when no exact match", () => {
    const groups = {
      "*": { requireMention: false },
    };
    const match = resolvePulseBoardGroupMatch({ groups, target: "#unknown" });
    expect(match.boardConfig).toBeUndefined();
    expect(match.wildcardConfig).toEqual({ requireMention: false });
  });

  it("defaults requireMention to true", () => {
    expect(
      resolvePulseBoardRequireMention({
        boardConfig: undefined,
        wildcardConfig: undefined,
      }),
    ).toBe(true);
  });

  it("uses board config for requireMention", () => {
    expect(
      resolvePulseBoardRequireMention({
        boardConfig: { requireMention: false },
        wildcardConfig: { requireMention: true },
      }),
    ).toBe(false);
  });
});

