/**
 * Normalize a PulseBoard messaging target.
 * Board targets start with "#", user targets are plain usernames.
 */
export function normalizePulseBoardTarget(raw: string): string | null {
  const trimmed = raw.trim().toLowerCase();
  if (!trimmed) {
    return null;
  }
  return trimmed;
}

/** Returns true when the target refers to a board (group) rather than a user DM. */
export function isBoardTarget(target: string): boolean {
  return target.startsWith("#");
}

/** Heuristic: does the raw string look like a PulseBoard target id? */
export function looksLikePulseBoardTargetId(raw: string): boolean {
  const trimmed = raw.trim();
  if (!trimmed) {
    return false;
  }
  // Board names: #something, usernames: alphanumeric with hyphens/underscores
  if (trimmed.startsWith("#") && trimmed.length > 1) {
    return true;
  }
  return /^[\w][\w.-]{0,62}$/.test(trimmed);
}

/** Normalize an allowlist entry (username). */
export function normalizePulseBoardAllowEntry(raw: string): string {
  return raw.trim().toLowerCase();
}

