export async function sendMessagePulseBoard(
  to: string,
  text: string,
  opts?: SendOptions,
): Promise<{ ok: boolean; messageId?: string }> {
  // Stub: log the outbound message for development/testing.
  const accountLabel = opts?.accountId ? ` (account: ${opts.accountId})` : "";
  const replyLabel = opts?.replyTo ? ` [reply-to: ${opts.replyTo}]` : "";
  console.debug(`[pulseboard] send${accountLabel}${replyLabel} -> ${to}: ${text.slice(0, 80)}...`);
  return { ok: true, messageId: `pb-${Date.now()}` };
}

